library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;
use work.processor_pkg.all;

entity processor is
    generic (
        INIT_FILE : string := ""  -- Path to hex file for memory initialization
    );
    port (
        clk : in std_logic;
        rst : in std_logic;
        int : in std_logic;
        -- Output port (directly from execute stage)
        output_port : out std_logic_vector(31 downto 0)
    );
end processor;

architecture structural of processor is

    -- ============================================================================
    -- Component Declarations
    -- ============================================================================

    component fetch_stage is
        port (
            clk : in std_logic;
            reset : in std_logic;
            PC_write_signal : in std_logic;
            Call_signal : in std_logic;
            Halt_signal : in std_logic;
            Jmp_Condition : in std_logic;
            Jmp_Unconditional : in std_logic;
            memory_to_PC : in std_logic;
            Immediate_execute : in std_logic_vector(31 downto 0);
            Immediate_fetch : in std_logic_vector(31 downto 0);
            memory_output : in std_logic_vector(31 downto 0);
            PC_out : out std_logic_vector(31 downto 0);
            PC_plus_4_out : out std_logic_vector(31 downto 0)
        );
    end component;

    component fetch_decode_register is
        port (
            clock : in std_logic;
            write_enable : in std_logic;
            reset : in std_logic;
            PC_plus_4 : in std_logic_vector(31 downto 0);
            instruction : in std_logic_vector(31 downto 0);
            PC_plus_4_out : out std_logic_vector(31 downto 0);
            instruction_out : out std_logic_vector(31 downto 0)
        );
    end component;

    component decode_stage is
        port (
            clk          : in  std_logic;
            rst          : in  std_logic;
            PC_Plus4     : in  std_logic_vector(31 downto 0);
            INT_Flag     : in  std_logic_vector(1 downto 0);
            RTI_Flag     : in  std_logic;
            INT_Signal_Flag : in  std_logic_vector(1 downto 0);
            IS_Immediate : in  std_logic;
            Flush_en     : in  std_logic;
            Stall_en     : in  std_logic;
            instr_in     : in  std_logic_vector(31 downto 0);
            reg_write_en : in  std_logic;
            reg_write_addr : in  std_logic_vector(2 downto 0);
            reg_write_data : in  std_logic_vector(31 downto 0);
            is_swap_in   : in  std_logic;
            rs1_data_out : out std_logic_vector(31 downto 0);
            rs2_data_out : out std_logic_vector(31 downto 0);
            rs1_addr_out : out std_logic_vector(2 downto 0);
            rs2_addr_out : out std_logic_vector(2 downto 0);
            rd_addr_out  : out std_logic_vector(2 downto 0);
            imm_out      : out std_logic_vector(31 downto 0);
            opcode_out   : out std_logic_vector(8 downto 0);
            PC_Plus4_out : out std_logic_vector(31 downto 0)
        );
    end component;

    component control_unit is
        port (
            clk              : in  std_logic;
            rst              : in  std_logic;
            instruction_opcode : in  std_logic_vector(8 downto 0);
            int_signal       : in  std_logic;
            mem_read         : out std_logic;
            mem_write        : out std_logic;
            reg_write        : out std_logic;
            use_immediate    : out std_logic;
            alu_function     : out std_logic_vector(2 downto 0);
            is_shadow_op     : out std_logic;
            is_swap_op       : out std_logic;
            is_int_op        : out std_logic;
            is_rti_op        : out std_logic;
            is_call_op       : out std_logic;
            is_ret_op        : out std_logic;
            is_jmp_op        : out std_logic;
            sp_enable        : out std_logic;
            jmp_unconditional : out std_logic;
            stall_pipeline   : out std_logic;
            flush_pipeline   : out std_logic
        );
    end component;

    component decode_execute_registers is
        port (
            clk          : in  std_logic;
            rst          : in  std_logic;
            Flush_en     : in  std_logic;
            Stall_en     : in  std_logic;
            alu_op       : in  std_logic_vector(2 downto 0);
            out_en       : in  std_logic;
            jmp_type     : in  std_logic_vector(1 downto 0);
            branch       : in  std_logic;
            flag_restore : in  std_logic;
            src1         : in  std_logic_vector(1 downto 0);
            carry        : in  std_logic;
            exec_in      : in  std_logic;
            is_immediate : in  std_logic;
            is_swap      : in  std_logic;
            mem_write_en : in  std_logic;
            mem_read_en  : in  std_logic;
            mem_write_addr: in  std_logic_vector(1 downto 0);
            mem_read_data: in  std_logic_vector(1 downto 0);
            stack_op     : in  std_logic_vector(1 downto 0);
            mem_to_reg   : in  std_logic;
            mem_to_pc    : in  std_logic;
            rs1_data_in  : in  std_logic_vector(31 downto 0);
            rs2_data_in  : in  std_logic_vector(31 downto 0);
            rs1_addr_in  : in  std_logic_vector(2 downto 0);
            rs2_addr_in  : in  std_logic_vector(2 downto 0);
            rd_addr_in   : in  std_logic_vector(2 downto 0);
            PC_Plus4_in  : in  std_logic_vector(31 downto 0);
            Flush_en_out     : out std_logic;
            Stall_en_out     : out std_logic;
            alu_op_out       : out std_logic_vector(2 downto 0);
            out_en_out       : out std_logic;
            jmp_type_out     : out std_logic_vector(1 downto 0);
            branch_out       : out std_logic;
            flag_restore_out : out std_logic;
            src1_out         : out std_logic_vector(1 downto 0);
            carry_out        : out std_logic;
            exec_out         : out std_logic;
            is_immediate_out : out std_logic;
            is_swap_out      : out std_logic;
            mem_write_en_out : out std_logic;
            mem_read_en_out  : out std_logic;
            mem_write_addr_out: out std_logic_vector(1 downto 0);
            mem_read_data_out: out std_logic_vector(1 downto 0);
            stack_op_out     : out std_logic_vector(1 downto 0);
            mem_to_reg_out   : out std_logic;
            mem_to_pc_out    : out std_logic;
            rs1_data_out     : out std_logic_vector(31 downto 0);
            rs2_data_out     : out std_logic_vector(31 downto 0);
            rs1_addr_out     : out std_logic_vector(2 downto 0);
            rs2_addr_out     : out std_logic_vector(2 downto 0);
            rd_addr_out      : out std_logic_vector(2 downto 0);
            PC_Plus4_out     : out std_logic_vector(31 downto 0)
        );
    end component;

    component execute_stage is
        port (
            clk                  : in  std_logic;
            reset                : in  std_logic;
            rs1_data_in          : in  std_logic_vector(31 downto 0);
            rs2_data_in          : in  std_logic_vector(31 downto 0);
            immediate_in         : in  std_logic_vector(31 downto 0);
            alu_op               : in  std_logic_vector(2 downto 0);
            alu_src_sel1         : in  std_logic_vector(1 downto 0);
            alu_src_sel2         : in  std_logic;
            use_alu_result       : in  std_logic;
            output_write_en      : in  std_logic;
            j_type               : in  std_logic_vector(1 downto 0);
            flag_restore         : in  std_logic;
            branch               : in  std_logic;
            carry_control        : in  std_logic;
            forwarding_rs1       : in  std_logic_vector(1 downto 0);
            forwarding_rs2       : in  std_logic_vector(1 downto 0);
            mem_data_forward     : in  std_logic_vector(31 downto 0);
            wb_data_forward      : in  std_logic_vector(31 downto 0);
            carry_out_mem        : in  std_logic;
            restored_ccr_in      : in  std_logic_vector(2 downto 0);
            alu_result_out       : out std_logic_vector(31 downto 0);
            ccr_out              : out std_logic_vector(2 downto 0);
            jump_signal          : out std_logic;
            execute_data_out     : out std_logic_vector(31 downto 0);
            output_port_out      : out std_logic_vector(31 downto 0);
            output_shifted_immediate : out std_logic_vector(31 downto 0)
        );
    end component;

    component exec_mem_register is
        port (
            clk                     : in  std_logic;
            reset                   : in  std_logic;
            stall                   : in  std_logic;
            flush                   : in  std_logic;
            pc_plus_4_in            : in  std_logic_vector(31 downto 0);
            execute_data_in         : in  std_logic_vector(31 downto 0);
            ccr_in                  : in  std_logic_vector(2 downto 0);
            or_carry_in             : in  std_logic;
            flag_restore_in         : in  std_logic;
            rdst_address_in         : in  std_logic_vector(4 downto 0);
            mem_write_data_in       : in  std_logic_vector(1 downto 0);
            mem_write_address_in    : in  std_logic_vector(1 downto 0);
            mem_read_enable_in      : in  std_logic;
            mem_write_enable_in     : in  std_logic;
            stack_operation_in      : in  std_logic_vector(1 downto 0);
            stack_flag_in           : in  std_logic;
            mem_to_reg_in           : in  std_logic;
            mem_to_pc_in            : in  std_logic;
            write_back_enable_in    : in  std_logic;
            rsrc1_in                : in  std_logic_vector(31 downto 0);
            pc_plus_4_out           : out std_logic_vector(31 downto 0);
            execute_data_out        : out std_logic_vector(31 downto 0);
            ccr_out                 : out std_logic_vector(2 downto 0);
            or_carry_out            : out std_logic;
            flag_restore_out        : out std_logic;
            rdst_address_out        : out std_logic_vector(4 downto 0);
            mem_write_data_out      : out std_logic_vector(1 downto 0);
            mem_write_address_out   : out std_logic_vector(1 downto 0);
            mem_read_enable_out     : out std_logic;
            mem_write_enable_out    : out std_logic;
            stack_operation_out     : out std_logic_vector(1 downto 0);
            stack_flag_out          : out std_logic;
            mem_to_reg_out          : out std_logic;
            mem_to_pc_out           : out std_logic;
            write_back_enable_out   : out std_logic;
            rsrc1_out               : out std_logic_vector(31 downto 0)
        );
    end component;

    component memory_interface is
        port (
            memory_address      : out std_logic_vector(31 downto 0);
            memory_input        : out std_logic_vector(31 downto 0);
            memory_write_enable : out std_logic;
            memory_read_enable  : out std_logic;
            PC                  : in std_logic_vector(31 downto 0);
            reset               : in std_logic;
            ALU_op              : in std_logic_vector(31 downto 0);
            SP                  : in std_logic_vector(31 downto 0);
            PC_plus_4           : in std_logic_vector(31 downto 0);
            Rs1                 : in std_logic_vector(31 downto 0);
            CCR                 : in std_logic_vector(31 downto 0);
            Memory_address_sel  : in std_logic_vector(1 downto 0);
            Memory_data_sel     : in std_logic_vector(1 downto 0);
            CU_write_enable     : in std_logic;
            CU_read_enable      : in std_logic;
            memory_output       : in std_logic_vector(31 downto 0);
            Memory_read_data    : out std_logic_vector(31 downto 0)
        );
    end component;

    component memory is
        generic (
            INIT_FILE : string := ""
        );
        port (
            memory_output       : out std_logic_vector(31 downto 0);
            memory_input        : in std_logic_vector(31 downto 0);
            memory_write_enable : in std_logic;
            memory_read_enable  : in std_logic;
            memory_address      : in std_logic_vector(31 downto 0);
            clock               : in std_logic
        );
    end component;

    component Stack_Pointer_Unit is
        port (
            clk              : in  std_logic;
            rst              : in  std_logic;
            SP_Update        : in  std_logic_vector(1 downto 0);
            Stack_Flag       : in  std_logic;
            SP_WB_In         : in  std_logic_vector(31 downto 0);
            SP_Write_En      : in  std_logic;
            Memory_Address_Out : out std_logic_vector(31 downto 0);
            SP_WriteBack_Out   : out std_logic_vector(31 downto 0)
        );
    end component;

    component forwarding_unit is
        port (
            rs1_ex        : in  std_logic_vector(4 downto 0);
            rs2_ex        : in  std_logic_vector(4 downto 0);
            rd_mem        : in  std_logic_vector(4 downto 0);
            rd_wb         : in  std_logic_vector(4 downto 0);
            reg_write_mem : in  std_logic;
            reg_write_wb  : in  std_logic;
            forward_a     : out std_logic_vector(1 downto 0);
            forward_b     : out std_logic_vector(1 downto 0)
        );
    end component;

    component hazard_detection_unit is
        port (
            ID_rs1         : in  std_logic_vector(2 downto 0);
            ID_rs2         : in  std_logic_vector(2 downto 0);
            IE_rd1         : in  std_logic_vector(2 downto 0);
            EX_mem_read    : in  std_logic;
            IM_mem_read    : in  std_logic;
            IM_mem_write   : in  std_logic;
            is_stall       : in  std_logic;
            EX_branch_taken: in  std_logic;
            pc_write       : out std_logic;
            IF_ID_en       : out std_logic;
            stall_en       : out std_logic
        );
    end component;

    -- ============================================================================
    -- Internal Signals
    -- ============================================================================

    -- Fetch Stage Signals
    signal fetch_pc              : std_logic_vector(31 downto 0);
    signal fetch_pc_plus_4       : std_logic_vector(31 downto 0);
    signal fetch_pc_write        : std_logic;
    signal fetch_immediate       : std_logic_vector(31 downto 0);

    -- IF/ID Register Signals
    signal ifid_pc_plus_4        : std_logic_vector(31 downto 0);
    signal ifid_instruction      : std_logic_vector(31 downto 0);
    signal ifid_write_enable     : std_logic;

    -- Decode Stage Signals
    signal decode_rs1_data       : std_logic_vector(31 downto 0);
    signal decode_rs2_data       : std_logic_vector(31 downto 0);
    signal decode_rs1_addr       : std_logic_vector(2 downto 0);
    signal decode_rs2_addr       : std_logic_vector(2 downto 0);
    signal decode_rd_addr        : std_logic_vector(2 downto 0);
    signal decode_immediate      : std_logic_vector(31 downto 0);
    signal decode_opcode         : std_logic_vector(8 downto 0);
    signal decode_pc_plus_4      : std_logic_vector(31 downto 0);

    -- Control Unit Signals
    signal cu_mem_read           : std_logic;
    signal cu_mem_write          : std_logic;
    signal cu_reg_write          : std_logic;
    signal cu_use_immediate      : std_logic;
    signal cu_alu_function       : std_logic_vector(2 downto 0);
    signal cu_is_shadow          : std_logic;
    signal cu_is_swap            : std_logic;
    signal cu_is_int             : std_logic;
    signal cu_is_rti             : std_logic;
    signal cu_is_call            : std_logic;
    signal cu_is_ret             : std_logic;
    signal cu_is_jmp             : std_logic;
    signal cu_sp_enable          : std_logic;
    signal cu_jmp_unconditional  : std_logic;
    signal cu_stall_pipeline     : std_logic;
    signal cu_flush_pipeline     : std_logic;

    -- ID/EX Register Signals (outputs)
    signal idex_flush_out        : std_logic;
    signal idex_stall_out        : std_logic;
    signal idex_alu_op           : std_logic_vector(2 downto 0);
    signal idex_out_en           : std_logic;
    signal idex_jmp_type         : std_logic_vector(1 downto 0);
    signal idex_branch           : std_logic;
    signal idex_flag_restore     : std_logic;
    signal idex_src1             : std_logic_vector(1 downto 0);
    signal idex_carry            : std_logic;
    signal idex_exec             : std_logic;
    signal idex_is_immediate     : std_logic;
    signal idex_is_swap          : std_logic;
    signal idex_mem_write_en     : std_logic;
    signal idex_mem_read_en      : std_logic;
    signal idex_mem_write_addr   : std_logic_vector(1 downto 0);
    signal idex_mem_read_data    : std_logic_vector(1 downto 0);
    signal idex_stack_op         : std_logic_vector(1 downto 0);
    signal idex_mem_to_reg       : std_logic;
    signal idex_mem_to_pc        : std_logic;
    signal idex_rs1_data         : std_logic_vector(31 downto 0);
    signal idex_rs2_data         : std_logic_vector(31 downto 0);
    signal idex_rs1_addr         : std_logic_vector(2 downto 0);
    signal idex_rs2_addr         : std_logic_vector(2 downto 0);
    signal idex_rd_addr          : std_logic_vector(2 downto 0);
    signal idex_pc_plus_4        : std_logic_vector(31 downto 0);

    -- Execute Stage Signals
    signal ex_alu_result         : std_logic_vector(31 downto 0);
    signal ex_ccr                : std_logic_vector(2 downto 0);
    signal ex_jump_signal        : std_logic;
    signal ex_execute_data       : std_logic_vector(31 downto 0);
    signal ex_output_port        : std_logic_vector(31 downto 0);
    signal ex_shifted_imm        : std_logic_vector(31 downto 0);
    signal ex_or_carry           : std_logic;

    -- EX/MEM Register Signals (outputs)
    signal exmem_pc_plus_4       : std_logic_vector(31 downto 0);
    signal exmem_execute_data    : std_logic_vector(31 downto 0);
    signal exmem_ccr             : std_logic_vector(2 downto 0);
    signal exmem_or_carry        : std_logic;
    signal exmem_flag_restore    : std_logic;
    signal exmem_rdst_addr       : std_logic_vector(4 downto 0);
    signal exmem_mem_write_data  : std_logic_vector(1 downto 0);
    signal exmem_mem_write_addr  : std_logic_vector(1 downto 0);
    signal exmem_mem_read_en     : std_logic;
    signal exmem_mem_write_en    : std_logic;
    signal exmem_stack_op        : std_logic_vector(1 downto 0);
    signal exmem_stack_flag      : std_logic;
    signal exmem_mem_to_reg      : std_logic;
    signal exmem_mem_to_pc       : std_logic;
    signal exmem_wb_enable       : std_logic;
    signal exmem_rsrc1           : std_logic_vector(31 downto 0);

    -- Memory Interface Signals
    signal mem_address           : std_logic_vector(31 downto 0);
    signal mem_write_data        : std_logic_vector(31 downto 0);
    signal mem_write_enable      : std_logic;
    signal mem_read_enable       : std_logic;
    signal mem_read_data         : std_logic_vector(31 downto 0);
    signal mem_output            : std_logic_vector(31 downto 0);

    -- Stack Pointer Unit Signals
    signal sp_memory_address     : std_logic_vector(31 downto 0);
    signal sp_writeback          : std_logic_vector(31 downto 0);

    -- Forwarding Unit Signals
    signal forward_a             : std_logic_vector(1 downto 0);
    signal forward_b             : std_logic_vector(1 downto 0);

    -- Hazard Detection Signals
    signal hazard_pc_write       : std_logic;
    signal hazard_ifid_en        : std_logic;
    signal hazard_stall_en       : std_logic;

    -- Write-back Signals
    signal wb_data               : std_logic_vector(31 downto 0);
    signal wb_reg_write          : std_logic;
    signal wb_rd_addr            : std_logic_vector(2 downto 0);

    -- Memory address selector (simplified)
    signal mem_addr_sel          : std_logic_vector(1 downto 0);
    signal mem_data_sel          : std_logic_vector(1 downto 0);

    -- CCR extended to 32 bits for memory interface
    signal ccr_extended          : std_logic_vector(31 downto 0);

begin

    -- ============================================================================
    -- FETCH STAGE
    -- ============================================================================
    fetch_inst: fetch_stage
        port map (
            clk               => clk,
            reset             => rst,
            PC_write_signal   => hazard_pc_write,
            Call_signal       => cu_is_call,
            Halt_signal       => '0',  -- TODO: Connect halt signal
            Jmp_Condition     => ex_jump_signal,
            Jmp_Unconditional => cu_jmp_unconditional,
            memory_to_PC      => exmem_mem_to_pc, -- TODO: it should come from memory_writeback_register
            Immediate_execute => ex_shifted_imm, -- TODO: it shouldn't be shifted
            Immediate_fetch   => mem_read_data, -- it should come from memory_output
            memory_output     => mem_read_data, -- it should come from memory_writeback_register
            PC_out            => fetch_pc,
            PC_plus_4_out     => fetch_pc_plus_4
        );

    -- ============================================================================
    -- IF/ID PIPELINE REGISTER
    -- ============================================================================
    ifid_write_enable <= hazard_ifid_en and (not cu_flush_pipeline) and (not cu_stall_pipeline);

    ifid_reg: fetch_decode_register
        port map (
            clock         => clk,
            write_enable  => ifid_write_enable,
            reset         => rst,
            PC_plus_4     => fetch_pc_plus_4,
            instruction   => mem_read_data,
            PC_plus_4_out => ifid_pc_plus_4,
            instruction_out => ifid_instruction
        );

    -- ============================================================================
    -- DECODE STAGE
    -- ============================================================================
    decode_inst: decode_stage
        port map (
            clk            => clk,
            rst            => rst,
            PC_Plus4       => ifid_pc_plus_4,
            INT_Flag       => "00",  -- TODO: Connect interrupt flags
            RTI_Flag       => cu_is_rti,
            INT_Signal_Flag => "00", -- TODO: Connect interrupt signal flags
            IS_Immediate   => cu_use_immediate,
            Flush_en       => cu_flush_pipeline,
            Stall_en       => hazard_stall_en,
            instr_in       => ifid_instruction,
            reg_write_en   => wb_reg_write,
            reg_write_addr => wb_rd_addr,
            reg_write_data => wb_data,
            is_swap_in     => cu_is_swap,
            rs1_data_out   => decode_rs1_data,
            rs2_data_out   => decode_rs2_data,
            rs1_addr_out   => decode_rs1_addr,
            rs2_addr_out   => decode_rs2_addr,
            rd_addr_out    => decode_rd_addr,
            imm_out        => decode_immediate,
            opcode_out     => decode_opcode,
            PC_Plus4_out   => decode_pc_plus_4
        );

    -- ============================================================================
    -- CONTROL UNIT
    -- ============================================================================
    control_inst: control_unit
        port map (
            clk               => clk,
            rst               => rst,
            instruction_opcode => decode_opcode,
            int_signal        => int,
            mem_read          => cu_mem_read,
            mem_write         => cu_mem_write,
            reg_write         => cu_reg_write,
            use_immediate     => cu_use_immediate,
            alu_function      => cu_alu_function,
            is_shadow_op      => cu_is_shadow,
            is_swap_op        => cu_is_swap,
            is_int_op         => cu_is_int,
            is_rti_op         => cu_is_rti,
            is_call_op        => cu_is_call,
            is_ret_op         => cu_is_ret,
            is_jmp_op         => cu_is_jmp,
            sp_enable         => cu_sp_enable,
            jmp_unconditional => cu_jmp_unconditional,
            stall_pipeline    => cu_stall_pipeline,
            flush_pipeline    => cu_flush_pipeline
        );

    -- ============================================================================
    -- ID/EX PIPELINE REGISTER
    -- ============================================================================
    idex_reg: decode_execute_registers
        port map (
            clk              => clk,
            rst              => rst,
            Flush_en         => cu_flush_pipeline,
            Stall_en         => hazard_stall_en,
            alu_op           => cu_alu_function,
            out_en           => '0',  -- TODO: Connect output enable
            jmp_type         => "00", -- TODO: Connect jump type
            branch           => cu_is_jmp,
            flag_restore     => cu_is_rti,
            src1             => "00", -- TODO: Connect src1 select
            carry            => '0',  -- TODO: Connect carry control
            exec_in          => '1',
            is_immediate     => cu_use_immediate,
            is_swap          => cu_is_swap,
            mem_write_en     => cu_mem_write,
            mem_read_en      => cu_mem_read,
            mem_write_addr   => "00", -- TODO: Connect memory address select
            mem_read_data    => "00", -- TODO: Connect memory data select
            stack_op         => "00", -- TODO: Connect stack operation
            mem_to_reg       => cu_mem_read,
            mem_to_pc        => cu_is_ret,
            rs1_data_in      => decode_rs1_data,
            rs2_data_in      => decode_rs2_data,
            rs1_addr_in      => decode_rs1_addr,
            rs2_addr_in      => decode_rs2_addr,
            rd_addr_in       => decode_rd_addr,
            PC_Plus4_in      => decode_pc_plus_4,
            Flush_en_out     => idex_flush_out,
            Stall_en_out     => idex_stall_out,
            alu_op_out       => idex_alu_op,
            out_en_out       => idex_out_en,
            jmp_type_out     => idex_jmp_type,
            branch_out       => idex_branch,
            flag_restore_out => idex_flag_restore,
            src1_out         => idex_src1,
            carry_out        => idex_carry,
            exec_out         => idex_exec,
            is_immediate_out => idex_is_immediate,
            is_swap_out      => idex_is_swap,
            mem_write_en_out => idex_mem_write_en,
            mem_read_en_out  => idex_mem_read_en,
            mem_write_addr_out => idex_mem_write_addr,
            mem_read_data_out => idex_mem_read_data,
            stack_op_out     => idex_stack_op,
            mem_to_reg_out   => idex_mem_to_reg,
            mem_to_pc_out    => idex_mem_to_pc,
            rs1_data_out     => idex_rs1_data,
            rs2_data_out     => idex_rs2_data,
            rs1_addr_out     => idex_rs1_addr,
            rs2_addr_out     => idex_rs2_addr,
            rd_addr_out      => idex_rd_addr,
            PC_Plus4_out     => idex_pc_plus_4
        );

    -- ============================================================================
    -- EXECUTE STAGE
    -- ============================================================================
    execute_inst: execute_stage
        port map (
            clk                   => clk,
            reset                 => rst,
            rs1_data_in           => idex_rs1_data,
            rs2_data_in           => idex_rs2_data,
            immediate_in          => ifid_instruction, -- TODO: Connect immediate with result directly from F/D register
            alu_op                => idex_alu_op,
            alu_src_sel1          => idex_src1,
            alu_src_sel2          => idex_is_immediate,
            use_alu_result        => idex_exec,
            output_write_en       => idex_out_en,
            j_type                => idex_jmp_type,
            flag_restore          => idex_flag_restore,
            branch                => idex_branch,
            carry_control         => idex_carry,
            forwarding_rs1        => forward_a,
            forwarding_rs2        => forward_b,
            mem_data_forward      => exmem_execute_data,
            wb_data_forward       => wb_data,
            carry_out_mem         => exmem_or_carry,
            restored_ccr_in       => exmem_ccr,
            alu_result_out        => ex_alu_result,
            ccr_out               => ex_ccr,
            jump_signal           => ex_jump_signal,
            execute_data_out      => ex_execute_data,
            output_port_out       => ex_output_port,
            output_shifted_immediate => ex_shifted_imm,
            or_carry_out          => ex_or_carry
        );

    -- ============================================================================
    -- EX/MEM PIPELINE REGISTER
    -- ============================================================================
    exmem_reg: exec_mem_register
        port map (
            clk                   => clk,
            reset                 => rst,
            stall                 => hazard_stall_en,
            flush                 => cu_flush_pipeline,
            pc_plus_4_in          => idex_pc_plus_4,
            execute_data_in       => ex_execute_data,
            ccr_in                => ex_ccr,
            or_carry_in           => ex_or_carry,
            flag_restore_in       => idex_flag_restore,
            rdst_address_in       => "00" & idex_rd_addr,
            mem_write_data_in     => idex_mem_write_addr,
            mem_write_address_in  => idex_mem_write_addr,
            mem_read_enable_in    => idex_mem_read_en,
            mem_write_enable_in   => idex_mem_write_en,
            stack_operation_in    => idex_stack_op,
            stack_flag_in         => '0',  -- TODO: Connect stack flag
            mem_to_reg_in         => idex_mem_to_reg,
            mem_to_pc_in          => idex_mem_to_pc,
            write_back_enable_in  => cu_reg_write,
            rsrc1_in              => idex_rs1_data,
            pc_plus_4_out         => exmem_pc_plus_4,
            execute_data_out      => exmem_execute_data,
            ccr_out               => exmem_ccr,
            or_carry_out          => exmem_or_carry,
            flag_restore_out      => exmem_flag_restore,
            rdst_address_out      => exmem_rdst_addr,
            mem_write_data_out    => exmem_mem_write_data,
            mem_write_address_out => exmem_mem_write_addr,
            mem_read_enable_out   => exmem_mem_read_en,
            mem_write_enable_out  => exmem_mem_write_en,
            stack_operation_out   => exmem_stack_op,
            stack_flag_out        => exmem_stack_flag,
            mem_to_reg_out        => exmem_mem_to_reg,
            mem_to_pc_out         => exmem_mem_to_pc,
            write_back_enable_out => exmem_wb_enable,
            rsrc1_out             => exmem_rsrc1
        );

    -- ============================================================================
    -- STACK POINTER UNIT
    -- ============================================================================
    sp_unit: Stack_Pointer_Unit
        port map (
            clk              => clk,
            rst              => rst,
            SP_Update        => exmem_stack_op,
            Stack_Flag       => exmem_stack_flag,
            SP_WB_In         => sp_writeback,
            SP_Write_En      => exmem_wb_enable,
            Memory_Address_Out => sp_memory_address,
            SP_WriteBack_Out => sp_writeback
        );

    -- ============================================================================
    -- MEMORY INTERFACE
    -- ============================================================================
    -- Memory address selection:
    -- "00" = PC (fetch), "01" = Reset/Int vector, "10" = ALU, "11" = SP
    mem_addr_sel <= "11" when exmem_stack_op /= "00" else
                    "10" when exmem_mem_read_en = '1' or exmem_mem_write_en = '1' else
                    "00";  -- Default to PC for fetch

    mem_data_sel <= "00";  -- Default to PC+4

    ccr_extended <= x"0000000" & "0" & exmem_ccr;

    mem_interface: memory_interface
        port map (
            memory_address      => mem_address,
            memory_input        => mem_write_data,
            memory_write_enable => mem_write_enable,
            memory_read_enable  => mem_read_enable,
            PC                  => fetch_pc,
            reset               => rst,
            ALU_op              => exmem_execute_data,
            SP                  => sp_memory_address,
            PC_plus_4           => exmem_pc_plus_4,
            Rs1                 => exmem_rsrc1,
            CCR                 => ccr_extended,
            Memory_address_sel  => mem_addr_sel,
            Memory_data_sel     => mem_data_sel,
            CU_write_enable     => exmem_mem_write_en,
            CU_read_enable      => exmem_mem_read_en,
            memory_output       => mem_output,
            Memory_read_data    => mem_read_data
        );

    -- ============================================================================
    -- MEMORY
    -- ============================================================================
    mem_inst: memory
        generic map (
            INIT_FILE => INIT_FILE
        )
        port map (
            memory_output       => mem_output,
            memory_input        => mem_write_data,
            memory_write_enable => mem_write_enable,
            memory_read_enable  => mem_read_enable,
            memory_address      => mem_address,
            clock               => clk
        );

    -- ============================================================================
    -- FORWARDING UNIT
    -- ============================================================================
    fwd_unit: forwarding_unit
        port map (
            rs1_ex        => "00" & idex_rs1_addr,
            rs2_ex        => "00" & idex_rs2_addr,
            rd_mem        => exmem_rdst_addr,
            rd_wb         => "00" & wb_rd_addr,
            reg_write_mem => exmem_wb_enable,
            reg_write_wb  => wb_reg_write,
            forward_a     => forward_a,
            forward_b     => forward_b
        );

    -- ============================================================================
    -- HAZARD DETECTION UNIT
    -- ============================================================================
    hazard_unit: hazard_detection_unit
        port map (
            ID_rs1          => decode_rs1_addr,
            ID_rs2          => decode_rs2_addr,
            IE_rd1          => idex_rd_addr,
            EX_mem_read     => idex_mem_read_en,
            IM_mem_read     => exmem_mem_read_en,
            IM_mem_write    => exmem_mem_write_en,
            is_stall        => cu_stall_pipeline,
            EX_branch_taken => ex_jump_signal,
            pc_write        => hazard_pc_write,
            IF_ID_en        => hazard_ifid_en,
            stall_en        => hazard_stall_en
        );

    -- ============================================================================
    -- WRITE-BACK (Simple MUX)
    -- ============================================================================
    wb_data <= mem_read_data when exmem_mem_to_reg = '1' else exmem_execute_data;
    wb_reg_write <= exmem_wb_enable;
    wb_rd_addr <= exmem_rdst_addr(2 downto 0);

    -- Output port assignment
    output_port <= ex_output_port;

end structural;
